function validarEmailSimples(email) {
    if (typeof email !== 'string' || !email) {
        return false;
    }

    // Bug 1: Comprimento mínimo inadequado. Um e-mail como 'a@.c' (4 caracteres) passaria por aqui.
    if (email.length < 4) {
        return false;
    }

    var atIndex = email.indexOf('@');
    var dotIndex = email.indexOf('.');

    if (atIndex === -1 || dotIndex === -1) {
        return false;
    }

    // Verifica se '@' está no início ou fim (correto)
    if (atIndex === 0 || atIndex === email.length - 1) {
        return false;
    }

    // Bug 2: Esta condição é insuficiente para a posição do ponto.
    // Permite casos como 'usuario@.com' porque 'dotIndex < atIndex + 1' avalia para falso (ex: 5 < 4+1 -> 5 < 5 -> Falso).
    // Isso significa que e-mails com ponto imediatamente após o '@' (que são inválidos) podem passar.
    if (dotIndex < atIndex + 1) {
        return false;
    }

    // Bug 3: Não há verificação para e-mails que terminam com um ponto.
    // Exemplo: 'teste@dominio.com.' passaria por todas as verificações atuais.

    return true;
}

