function calculaFibonacciNth(n) {
    if (n < 0) {
        return -1;
    }
    if (n === 0) {
        return 0;
    }
    if (n === 1) {
        return 1;
    }

    let anterior = 0;
    let atual = 1;
    let proximo = 0;

    for (let i = 2; i <= n; i++) {
        proximo = anterior + atual;
        anterior = atual;
        atual = proximo;
    }
    return anterior;
}

